#!/bin/bash
set -e
cd "$(dirname "$0")"

python3 -c "import base64; open('scripts/daily-agent.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ daily-agent.mjs 更新"

git add scripts/daily-agent.mjs
git commit -m "feat: daily-agent - 毎日GSC分析→Claude立案→タスク実行→記事生成の完全ループ"
git push origin main
echo ""
echo "🚀 Push完了！"
echo ""
echo "=== 毎日の実行フロー ==="
echo "Step 1: GSCデータ取得（APIキーあれば実データ、なければモック）"
echo "Step 2: Claude分析 → 今日のタスク3〜5件立案"
echo "Step 3: 自動タスクを実行"
echo "Step 4: 記事を1本生成（キーワードがなければClaudeが補充）"
echo "Step 5: git push → Vercel自動デプロイ"
echo ""
echo "=== crontab はこれだけでOK ==="
echo "0 7 * * * cd ~/Downloads/kyuryo-lab && bash scripts/daily-agent.sh >> scripts/logs/cron.log 2>&1"
echo ""
echo "不要になったcron（削除推奨）:"
echo "0 8 * * 1,4 ... run-pipeline.sh"
echo "0 9 * * 0   ... analyze-and-improve.mjs"
echo ""
echo "=== dry-runテスト ==="
node scripts/daily-agent.mjs --dry-run
